import numpy as np

def chebyshev_dist(p1, p2):
    return np.linalg.norm(np.array(p1) - np.array(p2), ord=np.inf)

if __name__ == "__main__":
    print(f"Dist: {chebyshev_dist([1.0, 9.0], [2.0, -5.2])}")
